import { access } from 'node:fs/promises'
import path from 'node:path'
import process from 'node:process'
import { fileURLToPath } from 'node:url'

const frontendRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '../../..')
const lcovPath = path.join(frontendRoot, 'coverage/e2e/lcov.info')

async function main() {
  try {
    await access(lcovPath)
    return
  }
  catch {
    // generated by Playwright global teardown when missing
  }

  const { finalizeCoverage, loadNextcovConfig } = await import('nextcov/playwright')
  const config = await loadNextcovConfig(path.join(frontendRoot, 'playwright.config.ts'))
  await finalizeCoverage({
    ...config,
    projectRoot: frontendRoot,
    outputDir: path.join(frontendRoot, config.outputDir),
    buildDir: path.join(frontendRoot, config.buildDir),
    sourceRoot: path.join(frontendRoot, config.sourceRoot),
  })
}

main().catch((error) => {
  console.error(error)
  process.exit(1)
})
